import itertools

def are_isomorphic(graph1, graph2):
    n1 = len(graph1)
    n2 = len(graph2)

    if n1 != n2:
        return False

    if n1 == 0:
        return True

    nodes1 = sorted(list(graph1.keys()))
    nodes2 = sorted(list(graph2.keys()))

    degrees1 = sorted([len(graph1[node]) for node in nodes1])
    degrees2 = sorted([len(graph2[node]) for node in nodes2])

    if degrees1 != degrees2:
        return False

    for p_perm in itertools.permutations(nodes2):
        mapping = {nodes1[i]: p_perm[i] for i in range(n1)}

        is_current_mapping_isomorphism = True

        for u_g1 in nodes1:
            neighbors_u_g1 = set(graph1[u_g1])
            mapped_u_g2 = mapping[u_g1]
            actual_neighbors_mapped_u_g2 = set(graph2[mapped_u_g2])

            transformed_neighbors_g2 = {mapping[v_g1] for v_g1 in neighbors_u_g1}

            if transformed_neighbors_g2 != actual_neighbors_mapped_u_g2:
                is_current_mapping_isomorphism = False
                break

        if is_current_mapping_isomorphism:
            return True

    return False
